function req(url,referer,isImage){
  return new MR(
    isImage?media(url):abs(url),
    "GET",
    [
      new KV("Referer",referer||BASE),
      new KV("Accept",isImage?"image/avif,image/webp,image/apng,image/*,*/*;q=0.8":"text/html,application/xhtml+xml,application/json;q=0.9,*/*;q=0.8")
