function currentQuery(){
  var keys=["ketsu_search","search","q"];
  try{
    var local=new URL(location.href);
    for(var i=0;i<keys.length;i++){
      var value=local.searchParams.get(keys[i])||"";
      if(value&&value!=="<searched>")return value;
    }
  }catch(error){}
  try{
    var meta=JSON.parse(saved().textContent||saved().innerText||"{}");
    var stored=new URL((meta.request&&meta.request.url)||BASE);
    for(var j=0;j<keys.length;j++){
      var savedValue=stored.searchParams.get(keys[j])||"";
      if(savedValue&&savedValue!=="<searched>")return savedValue;
    }
  }catch(error){}
  return "";
}
function card(doc){
  var rating=Number(doc.mbRating);
  var details=[];
  if(isFinite(rating)&&rating>0)details.push(rating.toFixed(1)+" rating");
  if(Number(doc.chapterCount)>0)details.push(doc.chapterCount+" chapters");
  return new Data(
    req(doc.posterMedium||doc.posterSmall||doc.poster||ICON,BASE,true),
    clean(doc.title)||clean(doc.englishTitle)||"Untitled",
    details.join(" - ")||"Search result",
