function fetchWithTimeout(url,timeout){
  return Promise.race([
    fetch(url,{method:"GET",headers:{"Accept":"application/json"},credentials:"same-origin",cache:"no-store"}),
    new Promise(function(resolve,reject){setTimeout(function(){reject(new Error("Search request timed out"));},timeout);})
  ]);
}
async function run(){
  try{
    var query=currentQuery();
    if(!query)return finish([messageCard("No search text","The app did not pass the search phrase.")]);
    var url=BASE+"collections/manga/documents/search?q="+encodeURIComponent(query)+"&query_by=title&page=1&per_page=40";
    var response=await fetchWithTimeout(url,10000);
    if(!response.ok)throw new Error("Atsu search returned HTTP "+response.status);
    var json=await response.json();
    var cards=(json.hits||[]).map(function(hit){return card(hit.document||{});});
    if(!cards.length)cards=[messageCard("No results","Try another title.")];
    finish(cards);
  }catch(error){
    finish([messageCard("Search error",clean(error&&error.message)||"Atsu search failed.")]);
  }
}

